  ('elementary-f29af906-moex-00328', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法規定，土地所有權人出售其自用住宅用地，其土地增值稅之核課，適用「一生一屋」之要 件，下列何者錯誤？', '["出售前1年內未曾供營業使用", "出售前持有該土地6年以上", "出售都市土地面積未超過一．五公畝部分或非都市土地面積未超過三．五公畝部分", "出售時土地所有權人與其配偶及未成年子女，無該自用住宅以外之房屋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00329', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅減免規則之規定，下列何者屬於免徵全部地價稅之情形？', '["依法劃定為古蹟保存區或編定為古蹟保存用地之土地，土地或建築物之使用及建造受限制", "私有土地無償供給政府機關、公立學校及軍事機關、部隊、學校使用，並在其使用期間以內", "私有土地經事業主管機關核准設立之私立農、林、漁、牧、工、礦試驗場，辦理5年以上，具有試 驗事實，其土地未作其他使用，並經該主管機關證明者", "區段徵收範圍內之土地，於辦理完成之日起"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00330', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法規定，下列敘述何者正確？', '["林地不得私有", "礦地不得私有", "因繼承而取得水源地之外國人，應於繼承發生日起3年內出售與本國人", "外國人為供自用、投資或公益之目的使用，得經申請核准後，取得墳場用途之土地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00331', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法相關規定，下列何者正確？', '["土地總登記，應由權利人按申報地價，繳納登記費千分之一", "土地總登記，應由義務人按申報地價，繳納登記費千分之二", "土地總登記，應由權利人按申報地價，繳納登記費千分之二", "土地總登記，應由義務人按申報現值，繳納登記費千分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00332', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法規定，遺贈之土地所有權移轉，申報移轉現值之審核標準，下列何者正確？', '["以遺贈人死亡日當期之公告土地現值為準", "以受遺贈人申報日當期之公告土地現值為準", "以遺贈人遺囑成立日當期之公告土地現值為準", "以遺贈人遺囑生效日當期之公告土地現值為準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00333', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '甲、乙、丙、丁、戊為A地之共有人，其應有部分各為五分之一。依共有土地之處理規定，下列敘 述何者正確？', '["甲不得單獨處分其應有部分", "縱使丙、丁不同意，甲、乙、丙三人仍得將A地設定抵押權", "乙不得單獨處分A地", "甲、乙、丙、丁、戊為公同共有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00334', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，下列敘述何者正確？', '["土地滅失時，應申請塗銷登記", "預告登記之塗銷，應提出原預告登記請求權人之同意書", "土地權利登記後，權利人之姓名或名稱有變更者，應申請更正登記", "私有土地所有權之拋棄，登記機關應辦理消滅登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00335', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅減免規則之規定，供公共通行之騎樓走廊地，其地上有建築改良物一層者，地價稅之課徵， 下列何者正確？', '["減徵五分之一", "減徵三分之一", "免徵", "減徵二分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00336', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，同一土地有二以上需用土地人申請徵收，且興辦事業性質相同者，應以下列何 者為核定原則？', '["依申請之先後", "依申請機關層級高者為優先", "依抽籤之結果", "由共同上級機關核定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00337', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '甲、乙、丙三人共有A地，甲之應有部分為五分之三，乙與丙之應有部分分別為五分之一，今甲欲 將A地無償設定地上權予丁。下列敘述何者正確？', '["甲得單獨將A地無償設定地上權予丁", "甲取得乙之同意後，縱使丙不同意，甲與乙仍得將A地無償設定地上權予丁", "甲取得乙之同意後，若丙不同意，甲與乙仍不得將A地無償設定地上權予丁", "共有土地無法設定地上權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
